head.script:
/**
 * 화 면 명 : Invoice List
 * 메뉴경로 : 국제물류/Accounting/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/il/acc/acinv/ac_102_01_01b.jsp
 * 작 성 자 : 이진우
 * 작 업 일 : 2026-02-20
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항

 * 수정이력 :
 *    - 2026-02-20      이진우    최초작성
 *    - 2026-02-23      이진우    T-7388 조치완료
 */
scwin.memJson = $c.data.getMemInfo();

scwin.clntNo = $c.gus.cfIsNull(scwin.memJson.clntNo) ? '' : scwin.memJson.clntNo;				//거래처코드
scwin.clntNm = scwin.memJson.clntNm;  //거래처명
scwin.userClsCd = scwin.memJson.userClsCd;  //사용자 구분코드
scwin.userId = scwin.memJson.userId;  //사용자

scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strPreDate = $c.date.addMonth(scwin.strCurDate, -1); //한달전

scwin.processType = "";

scwin.params = "";
scwin.jobgb = "";
scwin.iogb = "";
scwin.printDt = "";

scwin.txt_countRow = "";
scwin.hid_kcomcd = "DBEX"; //대표거래처 코드:no
scwin.hid_lobranCd = ""; //업무담당자구분코드

scwin.display3y = "";
scwin.display13y = "";
scwin.display15y = "";

scwin.onpageload = function() {
	// debugger;
    scwin.params = $c.data.getParameter();

	//해운 항공 구분
	scwin.jobgb = scwin.params.jobgb == null ? "S" : scwin.params.jobgb;
	//Import / Export 구분
	scwin.iogb = scwin.params.iogb == null ? "O" : scwin.params.iogb;    
    scwin.printDt = scwin.params.printDt == null ? "A" : scwin.params.printDt;

};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------    
scwin.onUdcCompleted = function () {
    console.log("scwin.clntNo", scwin.clntNo);
    console.log("scwin.clntNm", scwin.clntNm);
    console.log("scwin.userClsCd", scwin.userClsCd);
    console.log("scwin.userId", scwin.userId);
// debugger;

    const codeOptions = [
        { grpCd: "IL010", compID: "lc_transTyp" }
    ];
    $c.data.setCommonCode(codeOptions);

    lc_transTyp.setValue("");
    $c.gus.cfDisableObjects([lc_transTyp]);

    scwin.f_DefaultValue();
    scwin.f_initSetTab();

}

scwin.f_DefaultValue = function() {
// debugger;
    lc_jobgb.setValue(scwin.jobgb);
	lc_iogb.setValue(scwin.iogb);
	udc_fromToCalendar.setInitDate(scwin.strPreDate,scwin.strCurDate); //udc
	lc_printDt.setValue(scwin.printDt);
    // 내부거래처 이외에는 user 정보로 read only
    if (scwin.userClsCd != '01') {
        ed_cncd.setValue(scwin.clntNo);
        txt_cnnm.setValue(scwin.clntNm);
        $c.gus.cfDisableObjects([ed_cncd,txt_cnnm,img_cncd]);			
    } else {
        $c.gus.cfEnableObjects([ed_cncd,txt_cnnm,img_cncd]);					
    }

    //Value값: 가우스는 숫자 1/0을 주로 쓰지만, 웹스퀘어는 문자열 "1"/"0" 또는 "Y"/"N"으로 설정
    // chb_pre.checked = true;
    // lc_type.BindColVal = "1";
    chb_pre.setValue("T"); //미리보기 체크
    lc_type.setValue(1); //asis는 15탭 에 엑셀다운 밑에 콤보있음

    lc_printOp.setValue(0); //일반으로 설정

    // index 위치를 지정하지 않으면 자동으로 가장 마지막에 추가됨
    // addItem(value, label, index)
    lc_iogb.addItem("", "ALL");

};

//-------------------------------------------------------------------------
// function	name : f_initSetTab
// function	desc : Tab 초기화
//-------------------------------------------------------------------------
scwin.f_initSetTab = async function() {

    // $c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1, tr_tab_center2, tr_tab_center3, tr_tab_center4,tr_tab_center5,tr_tab_center6,tr_tab_center7,tr_tab_center8,tr_tab_center9
    //     ,tr_tab_center10,tr_tab_center11,tr_tab_center12,tr_tab_center13,tr_tab_center14,tr_tab_center15,tr_tab_center16,tr_tab_center17,tr_tab_center18]);
    // cfViewTab(0);
    // f_selectTabMenu(0);
    $c.gus.cfEnableObjects([tbc_main]);
    await tbc_main.setSelectedTabIndex(0);
    scwin.f_selectTabMenu(0);

};

//-------------------------------------------------------------------------
// function	name : f_selectTabMenu
// function	desc : Tab Menu 선택시 처리
//-------------------------------------------------------------------------
scwin.f_selectTabMenu = async function(idx) {	
    // debugger;
    console.log("f_selectTabMenu = " + idx)

    cnd_ed_picNo.setValue("");
    cnd_txt_picNm.setValue("");


    if (idx == 2) { // Excel Type 3 선택 시
    console.log("testtest");
        extraSlipInput.setStyle("display", "block");
    }
    else {
        extraSlipInput.setStyle("display", "none");
    }

    if (idx == 14) { // Excel Type 15 선택 시
        sty_lc_type.setStyle("display", "block");
    }
    else {
        sty_lc_type.setStyle("display", "none");
    }

    switch( idx ) {
        case 0: //Main tab
            scwin.processType = "TYPE1";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");
            // 웹스퀘어: 항목을 하나씩 추가
            lc_printDt.removeAll(); // 기존 데이터가 있다면 초기화
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.addItem("B", "ETD/ETA");
            lc_printDt.setValue("A");

            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.addItem("T", "Trans Order");
            lc_jobgb.setValue("S");

            break;
        case 1: //Other tab
            scwin.processType = "TYPE2";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");

            lc_printDt.removeAll(); // 기존 데이터가 있다면 초기화
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.addItem("B", "ETD/ETA");
            lc_printDt.setValue("A");

            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.addItem("T", "Trans Order");
            lc_jobgb.setValue("S");

            break;	
        case 2: //Other tab
            scwin.processType = "TYPE3";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "");            

            lc_printDt.removeAll(); // 기존 데이터가 있다면 초기화
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.addItem("B", "ETD/ETA");
            lc_printDt.setValue("A");

            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.addItem("T", "Trans Order");
            lc_jobgb.setValue("S");

            if(scwin.display3y != "Y") {
                gr_InvoiceType3_s.setStyle("display", "");
                udc_InvoiceType3.setGridId("gr_InvoiceType3_s"); //개인화버튼에 초기 그리드id 넘겨주기
                gr_InvoiceType3.setStyle("display", "none");    

            }

            break;
        case 3: //Other tab
            scwin.processType = "TYPE4";
            detailSearch.setStyle("display", "");
            detailSearch_type3.setStyle("display", "none");       

            lc_printDt.removeAll(); // 기존 데이터가 있다면 초기화
            lc_printDt.addItem("C", "On Board Date");
            lc_printDt.setValue("C");

            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.setValue("A");

            break;	
        case 4: //Other tab
            scwin.processType = "TYPE5";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");

            lc_printDt.removeAll(); // 기존 데이터가 있다면 초기화
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.setValue("A");

            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.setValue("S");

            lc_iogb.setValue("I");

            break;	
        case 5: //Other tab
            scwin.processType = "TYPE6";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");

            lc_printDt.removeAll(); // 기존 데이터가 있다면 초기화
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.setValue("A");

            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.setValue("S");

            lc_iogb.setValue("O");

            break;	
        case 6: //Other tab
            scwin.processType = "TYPE7";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");

            lc_printDt.removeAll(); // 기존 데이터가 있다면 초기화
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.setValue("A");

            lc_iogb.setValue("O");

            break;	
        case 7: //Other tab
            scwin.processType = "TYPE8";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");

            lc_printDt.removeAll(); 
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.addItem("B", "ETD");
            lc_printDt.addItem("C", "ETA");
            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.setValue("S");
            lc_iogb.setValue("O");

            break;	
        case 8: //Other tab
            scwin.processType = "TYPE9";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");
            lc_printDt.removeAll(); 
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.addItem("B", "ETD");
            lc_printDt.addItem("C", "ETA");
            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.setValue("S");
            lc_iogb.setValue("I");

            break;	
        case 9: //Other tab
            scwin.processType = "TYPE10";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");
            lc_printDt.removeAll(); 
