            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.addItem("", "All"); // 가우스의 "^All" 대응 (Value가 빈 값)
            //asis는 코딩이 없지만 널값 셋팅되어 추가
            lc_jobgb.setValue("S");
            lc_iogb.setValue("I");

            break;	

        case 11: //Other tab
            scwin.processType = "TYPE12";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");            

            lc_printDt.removeAll();
            // 2. 아이템 추가 (Value, Label 순서)
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.addItem("B", "ETD/ETA"); // 슬래시(/) 등 특수문자 그대로 입력 가능
            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.addItem("", "All"); // 가우스의 "^All" 대응 (Value가 빈 값)
            //asis는 코딩이 없지만 널값 셋팅되어 추가
            lc_jobgb.setValue("S");

            break;	

        case 12: //Other tab
            scwin.processType = "TYPE13";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "none");
            lc_printDt.removeAll();
            // 2. 아이템 추가 (Value, Label 순서)
            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.addItem("A", "Air");
            lc_jobgb.setValue("S");

            if(scwin.display13y != "Y") {
                gr_InvoiceType13.setStyle("display", ""); //lc_jobgb가 S이지만 초기에는 이걸로 되어있음
                udc_InvoiceType13.setGridId("gr_InvoiceType13"); //개인화버튼에 초기 그리드id 넘겨주기
                gr_InvoiceType13_s.setStyle("display", "none");    
