            lc_printDt.addItem("A", "Billing Date");
            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.setValue("S");
            lc_iogb.setValue("");
            ed_cncd.setValue("323142");
            txt_cnnm.setValue("한국앤컴퍼니");
            rd_enggb.setValue("1");

            break;

        case 16: //Other tab
            scwin.processType = "TYPE17";
            detailSearch.setStyle("display", "none");
            detailSearch_type3.setStyle("display", "");
            lc_printDt.removeAll();
            lc_printDt.addItem("A", "ETD");
            lc_printDt.setValue("A");
            lc_jobgb.removeAll(); // 기존 데이터가 있다면 초기화
            lc_jobgb.addItem("S", "Sea");
            lc_jobgb.setValue("S");

            break;

        case 17: //Other tab
            scwin.processType = "TYPE18";
            detailSearch.setStyle("display", "none");
