//---------------------------------------------------------
//조회
//---------------------------------------------------------
scwin.f_Retrieve = async function (e) {
//	if(ed_cncd.Text.trim()==""){
//		alert("Customer 를 입력하시오.");
//		ed_cncd.focus();
//		return;
//	}

    // VALIDATE
    let ret = await $c.gus.cfValidate([ed_bldtfrom, ed_bldtto])
    if (!ret) {  //validExp 가 yes일때 check
        return;
    }

    // ds_SearchParam.clearData();
    // ds_SearchParam.AddRow();
    dma_SearchParam.setEmptyValue();

switch (scwin.processType){
case "TYPE1":
    dma_SearchParam.set("kcomcd", "DBEX");	// 대표거래처코드
    dma_SearchParam.set("seaair", lc_jobgb.getValue().trim());
    dma_SearchParam.set("iogb", lc_iogb.getValue().trim());
    dma_SearchParam.set("certiNo", ed_certiNo.getValue().trim());
    dma_SearchParam.set("prtnGrpNo", ed_prtnGrpNo.getValue().trim());
    dma_SearchParam.set("slipNo", ed_slipNo.getValue().trim());
    dma_SearchParam.set("bilgClntNo", ed_cncd.getValue().trim());
    dma_SearchParam.set("bilgLodeptCd", ed_dept.getValue().trim());
    dma_SearchParam.set("bilgIntendDtFrom", ed_bldtfrom.getValue().trim());
    dma_SearchParam.set("bilgIntendDtTo", ed_bldtto.getValue().trim());
    dma_SearchParam.set("process", "TYPE1");

    //asis는 값이 들러가는데 파악필요
    // dma_SearchParam.set("type", 0);

    // tr_retrieveExcelType.Post();
    ds_InvoiceExcelType.removeAll();
    $c.sbm.execute(sbm_retrieveExcelType);

    // 필수! 여기서 멈추고 switch 문을 나갑니다.
    break;

case "TYPE2":
    dma_SearchParam.set("kcomcd", "DBEX");	// 대표거래처코드
    dma_SearchParam.set("seaair", lc_jobgb.getValue().trim());
    dma_SearchParam.set("iogb", lc_iogb.getValue().trim());
    dma_SearchParam.set("certiNo", ed_certiNo.getValue().trim());
    dma_SearchParam.set("prtnGrpNo", ed_prtnGrpNo.getValue().trim());
    dma_SearchParam.set("slipNo", ed_slipNo.getValue().trim());
    dma_SearchParam.set("bilgClntNo", ed_cncd.getValue().trim());
    dma_SearchParam.set("bilgLodeptCd", ed_dept.getValue().trim());
    dma_SearchParam.set("bilgIntendDtFrom", ed_bldtfrom.getValue().trim());
    dma_SearchParam.set("bilgIntendDtTo", ed_bldtto.getValue().trim());
    dma_SearchParam.set("process", "TYPE2");

    ds_InvoiceExcelType2.removeAll();
    $c.sbm.execute(sbm_retrieveExcelType2);

    break;

case "TYPE3":
    dma_SearchParam.set("kcomcd", "DBEX");	// 대표거래처코드
    dma_SearchParam.set("seaair", lc_jobgb.getValue().trim());
    dma_SearchParam.set("iogb", lc_iogb.getValue().trim());
