};

//------------------------------------------------------------------------
// 조회 조건 필드 초기화
//------------------------------------------------------------------------
scwin.f_FieldClear = function () {
 	scwin.f_DefaultValue();

}

scwin.f_FieldClear2 = function () {
 	txt_dscds.setValue("");

}

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();

};

scwin.sbm_retrieveExcelType_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code == 0) {
        if (ds_InvoiceExcelType.getRowCount() > 0) {
            gr_InvoiceType1.setFocusedCell(0, "seaair");
            tbx_totalRows.setValue(ds_InvoiceExcelType.getRowCount()); // 조회된 건수를 매출입항목Grid 하단에 표시한다.	

        } else {
            $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다. 

        }
    }

	if(lc_jobgb.getValue()=="S"){
		// 헤더 컬럼의 ID가 "aaf"인 경우
        gr_InvoiceType1.setHeaderValue("h_tcwht", "Chargeable W/T(Kg)");
        gr_InvoiceType1.setHeaderValue("h_aaf", "O/F Total");
		// gr_InvoiceType1.ColumnProp("fltno", "Show") =false    ;
        gr_InvoiceType1.setColumnVisible("fltno", false);

	}else{
		gr_InvoiceType1.setHeaderValue("h_tcwht", "Chargeable W/T(Kg)");
        gr_InvoiceType1.setHeaderValue("h_aaf", "A/F Total");
	}

};

scwin.tbc_main_ontabclick = function (tabId, index) {
    let idx = index;
    console.log("tbc_main_ontabclick tabId,index = " + tabId + " : " + index);

    scwin.f_selectTabMenu(idx);

};

scwin.sbm_retrieveExcelType2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        if (ds_InvoiceExcelType2.getRowCount() > 0) {
            tbx_totalRows2.setValue(ds_InvoiceExcelType2.getRowCount()); // 조회된 건수를 매출입항목Grid 하단에 표시한다.	

        } else {
            $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다. 

        }
    }

// debugger;

//해상 운임일 경우 불필요한 컬럼 삭제
	if(lc_jobgb.getValue()=="S"){
		//Weight, C/Weight hidden
        gr_InvoiceType2.setColumnVisible("tcwht", false);
