        gr_InvoiceType2.setColumnVisible("inps", false);
        gr_InvoiceType2.setColumnVisible("inpw", false);
        gr_InvoiceType2.setColumnVisible("anss", false);
        gr_InvoiceType2.setColumnVisible("answ", false);
        gr_InvoiceType2.setColumnVisible("aocs", false);
        gr_InvoiceType2.setColumnVisible("aocw", false);

        gr_InvoiceType2.setColumnVisible("trds", true);
        gr_InvoiceType2.setColumnVisible("trdw", true);
        gr_InvoiceType2.setColumnVisible("trdvs", true);
        gr_InvoiceType2.setColumnVisible("trdvw", true);

	}else{

        gr_InvoiceType2.setColumnVisible("tcwht", true);

        gr_InvoiceType2.setColumnVisible("col1", false);
        gr_InvoiceType2.setColumnVisible("col2", false);

        gr_InvoiceType2.setColumnVisible("atcs", true);
        gr_InvoiceType2.setColumnVisible("atcw", true);
        gr_InvoiceType2.setColumnVisible("stcs", true);
        gr_InvoiceType2.setColumnVisible("stcw", true);

        gr_InvoiceType2.setColumnVisible("inus", true);
        gr_InvoiceType2.setColumnVisible("inuw", true);
        gr_InvoiceType2.setColumnVisible("inps", true);
        gr_InvoiceType2.setColumnVisible("inpw", true);

        gr_InvoiceType2.setColumnVisible("anss", true);
        gr_InvoiceType2.setColumnVisible("answ", true);
        gr_InvoiceType2.setColumnVisible("aocs", true);
        gr_InvoiceType2.setColumnVisible("aocw", true);

        gr_InvoiceType2.setColumnVisible("trds", false);
        gr_InvoiceType2.setColumnVisible("trdw", false);
        gr_InvoiceType2.setColumnVisible("trdvs", false);
        gr_InvoiceType2.setColumnVisible("trdvw", false);

