        gr_InvoiceType2.setColumnVisible("lssw", false);
        gr_InvoiceType2.setColumnVisible("slcs", false);
        gr_InvoiceType2.setColumnVisible("slcw", false);

	}
//칼럼 헤더 변경
	if(lc_jobgb.getValue()=="S"){								 

        gr_InvoiceType2.setHeaderValue("h_aafs", "OCF");
        gr_InvoiceType2.setHeaderValue("h_aafw", "OCF(W)");
