scwin.sbm_retrieveExcelType8_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code == 0) {
        if (ds_InvoiceExcelType8.getRowCount() > 0) {
            tbx_totalRows8.setValue(ds_InvoiceExcelType8.getRowCount()); // 조회된 건수를 매출입항목Grid 하단에 표시한다.	

            //자료가 존재 할때
            let cntr1 = "";
            let cntr2 = "";
            let cntr3 = "";

            // for (i=1; i<=ds_InvoiceExcelType8.CountRow; i++) {
            for (i=0; i < ds_InvoiceExcelType8.getRowCount(); i++) {
                cntr1 = ds_InvoiceExcelType8.getCellData(i,"cntPart1");
                cntr2 = ds_InvoiceExcelType8.getCellData(i,"cntPart2");
                cntr3 = ds_InvoiceExcelType8.getCellData(i,"cntPart3");

                if(cntr1=="" || cntr1 == 0){
                    ds_InvoiceExcelType8.setCellData(i,"cntPart1", 0);
                } else {				
                    for (j=0; j < ds_InvoiceExcelType8.getRowCount(); j++) {
                        if(ds_InvoiceExcelType8.getCellData(j,"cntPart1")==cntr1){					
                            if(i<j){
                                ds_InvoiceExcelType8.setCellData(j,"cntPart1", 0);						
                            } else {
                                ds_InvoiceExcelType8.setCellData(j,"cntPart1", 1);						
                            }					
                        }
                    }
                }

                if(cntr2=="" || cntr2 == 0){
                    ds_InvoiceExcelType8.setCellData(i,"cntPart2", 0);
                } else {				
                    for (j=0; j < ds_InvoiceExcelType8.getRowCount(); j++) {
                        if(ds_InvoiceExcelType8.getCellData(j,"cntPart2")==cntr2){					
                            if(i<j){
                                ds_InvoiceExcelType8.setCellData(j,"cntPart2", 0);						
                            } else {
                                ds_InvoiceExcelType8.setCellData(j,"cntPart2", 1);						
                            }					
                        }
                    }
                }

                if(cntr3=="" || cntr3 == 0){
                    ds_InvoiceExcelType8.setCellData(i,"cntPart3", 0);
                } else {				
                    for (j=1; j < ds_InvoiceExcelType8.getRowCount(); j++) {
                        if(ds_InvoiceExcelType8.getCellData(j,"cntPart3")==cntr3){					
                            if(i<j){
                                ds_InvoiceExcelType8.setCellData(j,"cntPart3", 0);						
                            } else {
                                ds_InvoiceExcelType8.setCellData(j,"cntPart3", 1);						
                            }					
                        }
                    }
                }

                ds_InvoiceExcelType8.setCellData(i,"cntr1", ds_InvoiceExcelType8.getCellData(i,"cnt1") + Number(ds_InvoiceExcelType8.getCellData(i,"cntPart1")) );
                ds_InvoiceExcelType8.setCellData(i,"cntr2", ds_InvoiceExcelType8.getCellData(i,"cnt2") + Number(ds_InvoiceExcelType8.getCellData(i,"cntPart2")) );
                ds_InvoiceExcelType8.setCellData(i,"cntr3", ds_InvoiceExcelType8.getCellData(i,"cnt3") + Number(ds_InvoiceExcelType8.getCellData(i,"cntPart3")) );

            }

        } else {
            $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다. 

        }
    }
};

