///////////////////////////////////////////////////////////////////////////////////////////
// 프린트 -- Invoice List Type Print 
///////////////////////////////////////////////////////////////////////////////////////////
scwin.f_Print = async function () {

    // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
    if(lc_jobgb.getValue() == ""){
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("Job Type"));
        lc_jobgb.focus();
        return;
    }	   
    /*
    if(lc_iogb.getValue().trim()== ""){
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("Export/Import"));
        lc_iogb.focus();
        return;
    }	
    */	
    if(ed_bldtfrom.getValue().trim()=='' || ed_bldtto.getValue().trim()==''){
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("ETD"));
        ed_bldtfrom.focus();
        return;
    }
    if (!$c.gus.cfIsAfterDate(ed_bldtfrom.getValue().trim(), ed_bldtto.getValue().trim(), false)) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        return;
    }	

    let odiParam = {};
    let reportFile = "";
