scwin.f_Print_Invoice = function () {
	if (scwin.processType == "TYPE3") {
		scwin.f_Print_InvoiceType3();
	} else if (scwin.processType == "TYPE12") {
		scwin.f_Print_InvoiceType12()
	} else {
		alert("선택한 Type에서는 출력이 불가합니다.");
		return;
	}

};

