// Invoice Type Print ExcelTpye3
///////////////////////////////////////////////////////////////////////////////////////////
scwin.f_Print_InvoiceType3 = async function () {

		// Type3 에 데이터가 있는지 확인 
		// if ( ds_InvoiceExcelType3.CountRow < 1 ) {
        if ( ds_InvoiceExcelType3.getRowCount() < 1 ) {
			$c.win.alert("There is no data in Excel Type3");
			return;
		}

        ///////////
		// Type3 에 선택한 데이터가 있는지 확인 
		let choice_count = 0;				

        // 1. 체크된 행의 데이터만 JSON 배열로 가져오기
        let checkedData = ds_InvoiceExcelType3.getMatchedJSON("choice", "T"); 

        // 2. prtnGrpNo 값만 추출하여 Set에 담기 (Set은 자동으로 중복을 제거함)
        let uniqueGrpNos = new Set(checkedData.map(function(item) {
            return item.prtnGrpNo;
        }));

        // 3. 중복 제거된 카운트 결과
        choice_count = uniqueGrpNos.size;
        /////
		if ( choice_count == 0 ) {
			$c.win.alert("There is no Choice in Excel Type3");
			return;			
		}

        if (chb_pre.getValue() == "T" && chb_sav.getValue() == "T") {
            $c.win.alert("미리보기 와 바로저장을 동시에 체크할 수 없습니다.");
            chb_pre.checkAll(false);
            chb_sav.checkAll(false);
            return false;
        }

		// 선택된데이터중 중복을 제거하여 Invoice OZ용 데이터셋 생성 ///////////////////////////////////////////////////////////////////////////////		
		ds_InvoiceOZ.removeAll();

		// 비교시 합일유무 확인용 변수 
		let check_sum;				

	    // 전체 데이터 만큼 루프를 돌리고, 
		for( let j=0; j < ds_InvoiceExcelType3.getRowCount(); j++) {

		    // 개중에 선택된 것만 추려낸 다음 
			if ( ds_InvoiceExcelType3.getCellData( j, "choice") == "T" ) {

			    // OZ용 데이터 셋에 저장된 데이터와 비교해서 없는것만 새로입력 한다.  비교 구분자는 Invoice_NO 
				check_sum = false;

				for( let k=0; k < ds_InvoiceOZ.getRowCount(); k++) {					
					// alert("k Loop Activate =>" + k + "\n ds_InvoiceOZ.getCellData(k,prtnGrpNo) => " + ds_InvoiceOZ.getCellData(k,"prtnGrpNo") + "\n ds_InvoiceExcelType3.getCellData( j, prtnGrpNo)  => " + ds_InvoiceExcelType3.getCellData( j, "prtnGrpNo")  );
					if( ds_InvoiceOZ.getCellData(k,"prtnGrpNo") == ds_InvoiceExcelType3.getCellData( j, "prtnGrpNo") ) {
					    // alert("check_sum = true activate" );
        				check_sum = true;										
					}
				} 				

				// alert( " J Loop Count => " + j + "\ncheck_sum => " + check_sum );				   				
				if( check_sum == false ){				
					// ds_InvoiceOZ.AddRow();					
					ds_InvoiceOZ.insertRow();

                    let invoiceOzCnt = ds_InvoiceOZ.getRowCount();

					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "kcomcd"     , ds_InvoiceExcelType3.getCellData( j, "kcomcd"     )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "prtnGrpNo"  , ds_InvoiceExcelType3.getCellData( j, "prtnGrpNo"  )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "seaair"     , ds_InvoiceExcelType3.getCellData( j, "seaair"     )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "iogb"       , ds_InvoiceExcelType3.getCellData( j, "iogb"       )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "bilgClntNo" , ds_InvoiceExcelType3.getCellData( j, "bilgClntNo" )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "updid"      , ds_InvoiceExcelType3.getCellData( j, "updid"      )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "summary"    , ds_InvoiceExcelType3.getCellData( j, "summary"    )) ;	
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "bilgPicNm"  , ds_InvoiceExcelType3.getCellData( j, "bilgPicNm"  )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "blNo"  	  , ds_InvoiceExcelType3.getCellData( j, "blNo"  	   )) ;										
				}
			}
		}

		// 정리된 InvoiceOZ데이터를 기준으로 InvoiceOZ를 출력한다 ///////////////////////////////////////////////////////////////////////////////	

		await $c.win.alert("You choose " + choice_count + " Invoice Numbers \nPress 'OK'");		

	  	// $c.gus.OZStartBatch();

        let odiParam = {};
        let reportFile = "";
        let odiName = "";

        let blNo = "";
        let prtnGrpNo = "";

		for( let m=0; m < ds_InvoiceOZ.getRowCount(); m++) {

				if(ds_InvoiceOZ.getCellData(m,"seaair")=="S"){
                    odiParam = {
                        //odiParam.add("KCOMCD"      , ds_InvoiceOZ.NameValue(m,"kcomcd")    );
                        "KCOMCD": ds_InvoiceOZ.getCellData(m,"kcomcd"),
                        "PRTN_GRP_NO": ds_InvoiceOZ.getCellData(m,"prtnGrpNo"),
                        "SEAAIR": 'S',
                        "IOGB": ds_InvoiceOZ.getCellData(m,"iogb"),
                        "BILG_CLNT_NO": ds_InvoiceOZ.getCellData(m,"bilgClntNo"),
                        "USER_ID": ds_InvoiceOZ.getCellData(m,"updid"),
                        "TYPE": lc_printOp.getValue(),
                        "RMK": rd_rmk.getValue(),
                        "REMARK": ds_InvoiceOZ.getCellData(m,"summary"),
                        "ENG": rd_enggb.getValue()

                    };

					if(ds_InvoiceOZ.getCellData(m,"bilgPicNm") !=""){
						// odiParam.add("PIC", "1");		//담당자 있다
                        odiParam["PIC"] = "1";
					}else{
						// odiParam.add("PIC", "2");		//담당자 없다
                        odiParam["PIC"] = "2";
					}

                    //////////////////////////////////////////////
                    reportFile = "/il/acc/ac_101_01_01_sea_01.ozr";
                    odiName = "ac_101_01_01_sea"; //ac_101_01_01_sea_01 -> ac_101_01_01_sea

//////
                    console.log("type3 invoice print seaair ss::",odiParam);

                    blNo = ds_InvoiceOZ.getCellData(m,"blNo");
                    prtnGrpNo = ds_InvoiceOZ.getCellData(m,"prtnGrpNo");

                    let viewerParam = {};
                    if (chb_pre.getValue() == "T" && chb_sav.checked != "T") {    // 미리보기 체크시

                        viewerParam.useprogressbar = false;
                        viewerParam.zoom = 90;
                        viewerParam.mode = "preview";

                        let data = {
                            "reportName": reportFile,
                            "odiParam": odiParam,
                            "viewerParam": viewerParam,
                            "odiName": odiName,
                            "formParam": {}

                        };

                        await scwin.openPopup(data);

                    } else if (chb_sav.getValue() == "T" && chb_pre.getValue() != "T") {   //바로저장 체크시
                        viewerParam.useprogressbar = false;
                        viewerParam.mode = "export";

                        let data = {
                            "reportName": reportFile,
                            "odiParam": odiParam,
                            "viewerParam": viewerParam,
                            "odiName": odiName,
                            "formParam": {}
                        };

                        let saveOptions = {
                            "exportFilename": blNo + "_INVOICE" + "_" + prtnGrpNo,
                            "exportPath": "C:\\OZExport",
                            "exportFormat": "pdf",
                            "exportMode": "silent",
                            "exportConfirmsave": "false"
                        };

                        $c.ext.downloadOzReport(data, saveOptions);
                    } else if (chb_pre.getValue() != "T" && chb_sav.getValue() != "T") {   //인쇄 옵션창 표시 없이 바로 출력
                        viewerParam.useprogressbar = true;

                        let data = {
                            "reportName": reportFile,
                            "odiParam": odiParam,
                            "viewerParam": viewerParam,
                            "odiName": odiName,
                            "formParam": {}

                        }
                        await $c.ext.printOzReport(data);
                    }
////////////        
		 		} else {

                    odiParam = {
                        //odiParam.add("KCOMCD"      , ds_InvoiceOZ.NameValue(m,"kcomcd")    );
                        "KCOMCD": ds_InvoiceOZ.getCellData(m,"kcomcd"),
                        "PRTN_GRP_NO": ds_InvoiceOZ.getCellData(m,"prtnGrpNo"),
                        "SEAAIR": 'A',
                        "IOGB": ds_InvoiceOZ.getCellData(m,"iogb"),
                        "BILG_CLNT_NO": ds_InvoiceOZ.getCellData(m,"bilgClntNo"),
                        "USER_ID": ds_InvoiceOZ.getCellData(m,"updid"),
                        "TYPE": lc_printOp.getValue(),
                        "RMK": rd_rmk.getValue(),
                        "REMARK": ds_InvoiceOZ.getCellData(m,"summary"),
                        "ENG": rd_enggb.getValue()

                    };

					if(ds_InvoiceOZ.getCellData(m,"bilgPicNm") !=""){
						// odiParam.add("PIC", "1");		//담당자 있다
                        odiParam["PIC"] = "1";
					}else{
						// odiParam.add("PIC", "2");		//담당자 없다
                        odiParam["PIC"] = "2";
					}

                    //////////////////////////////////////////////
                    reportFile = "/il/acc/ac_101_01_01_air_01.ozr";
                    odiName = "ac_101_01_01_air"; //ac_101_01_01_air_01 -> ac_101_01_01_air

//////
                    console.log("type3 invoice print seaair ss아니면::",odiParam);

                    blNo = ds_InvoiceOZ.getCellData(m,"blNo");
                    prtnGrpNo = ds_InvoiceOZ.getCellData(m,"prtnGrpNo");

                    let viewerParam = {};
