///////////////////////////////////////////////////////////////////////////////////////////
//Invoice Type Print ExcelTpye12
///////////////////////////////////////////////////////////////////////////////////////////
scwin.f_Print_InvoiceType12 = async function () {

	// Type12 에 데이터가 있는지 확인 
	if ( ds_InvoiceExcelType12.getRowCount() < 1 ) {
		$c.win.alert("There is no data in Excel Type12");
		return;
	}

	// Type12 에 선택한 데이터가 있는지 확인 
	let choice_count = 0;				
	for( let i = 0; i < ds_InvoiceExcelType12.getRowCount(); i++ ){
        if ( ds_InvoiceExcelType12.getCellData(i,	"choice") == "T" ) {
			choice_count = choice_count + 1;			
		}
	} 				
	if ( choice_count == 0 ) {
		$c.win.alert("There is no Choice in Excel Type12");
		return;			
	}
    if (chb_pre.getValue() == "T" && chb_sav.getValue() == "T") {
        $c.win.alert("미리보기 와 바로저장을 동시에 체크할 수 없습니다.");
        chb_pre.checkAll(false);
        chb_sav.checkAll(false);
        return false;
    }

	// 선택된데이터중 중복을 제거하여 Invoice OZ용 데이터셋 생성 ///////////////////////////////////////////////////////////////////////////////		
	ds_InvoiceOZ.removeAll();

	// 비교시 합일유무 확인용 변수 
	let check_sum;				

    // 전체 데이터 만큼 루프를 돌리고, 
	for( let j=0; j < ds_InvoiceExcelType12.getRowCount(); j++) {
	    // 개중에 선택된 것만 추려낸 다음 
		if ( ds_InvoiceExcelType12.getCellData( j, "choice") == "T" ) {
			    // OZ용 데이터 셋에 저장된 데이터와 비교해서 없는것만 새로입력 한다. 비교 구분자는 Invoice_NO 
				check_sum = false;
				for( let k=0; k < ds_InvoiceOZ.getRowCount(); k++) {					
					if( ds_InvoiceOZ.getCellData(k,"prtnGrpNo") == ds_InvoiceExcelType12.getCellData( j, "prtnGrpNo") ) {
     					check_sum = true;										
					}
				} 				

				if( check_sum == false ){				
					// ds_InvoiceOZ.AddRow();					
					ds_InvoiceOZ.insertRow();

                    let invoiceOzCnt = ds_InvoiceOZ.getRowCount();

					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "kcomcd"     , ds_InvoiceExcelType12.getCellData( j, "kcomcd"     )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "prtnGrpNo"  , ds_InvoiceExcelType12.getCellData( j, "prtnGrpNo"     )) ;
					ds_InvoiceOZ.setCellData(invoiceOzCnt-1, "seaair"     , ds_InvoiceExcelType12.getCellData( j, "seaAirCls"     )) ;
