  scwin.f_DownExcelSheet = async function () {

// debugger;

	var vObjGrd;
	var sheetTitle;
	var cntRow = scwin.txt_countRow;

	if(cntRow != "0"){
		// cfrm = confirm("Invoice List 를 EXCEL로 다운로드 받으시겠습니까?");
        if (await $c.win.confirm("Invoice List 를 EXCEL로 다운로드 받으시겠습니까?")) {

			if(scwin.processType=="TYPE1"){
				vObjGrd = "gr_InvoiceType1";
				sheetTitle = "Invoice List Type1";
			}else if(scwin.processType=="TYPE2"){
				vObjGrd = "gr_InvoiceType2";
				if(lc_jobgb.getValue()=="S"){
					sheetTitle = "해상운임청구";
				}else{
					sheetTitle = "항공운임청구";
				}
			}else if(scwin.processType=="TYPE3"){
				if(lc_jobgb.getValue()=="S"){
                    vObjGrd = "gr_InvoiceType3_s";
                } else if(lc_jobgb.getValue()=="A") {
                    vObjGrd = "gr_InvoiceType3";
                } else if(lc_jobgb.getValue()=="T") {
                    vObjGrd = "gr_InvoiceType3_s";
                }
                sheetTitle = "Invoice List Type3";

			}else if(scwin.processType=="TYPE4"){
				vObjGrd = "gr_InvoiceType4";
				sheetTitle = "르노삼성 Invoice List";
			}else if(scwin.processType=="TYPE5"){
				vObjGrd = "gr_InvoiceType5";
				sheetTitle = "Invoice List_일진머티리얼_수입";
			}else if(scwin.processType=="TYPE6"){
				vObjGrd = "gr_InvoiceType6";
				sheetTitle = "Invoice List_일진머티리얼_수출";
			}else if(scwin.processType=="TYPE7"){
				vObjGrd = "gr_InvoiceType7";
				sheetTitle = "Invoice List_일진머티리얼_항공수출";
			}else if(scwin.processType=="TYPE8"){
				vObjGrd = "gr_InvoiceType8";
				sheetTitle = "Invoice List_화승_해상수출";
			}else if(scwin.processType=="TYPE9"){
				vObjGrd = "gr_InvoiceType9";
				sheetTitle = "Invoice List_화승_해상수입";
			}else if(scwin.processType=="TYPE10"){
				vObjGrd = "gr_InvoiceType10";
				sheetTitle = "Invoice List_화승_항공수입";
			}else if(scwin.processType=="TYPE11"){
				vObjGrd = "gr_InvoiceType11";
				sheetTitle = "Invoice List Type11";
			}else if(scwin.processType=="TYPE12"){
				vObjGrd = "gr_InvoiceType12";
				sheetTitle = "Invoice List Type12";
			}else if(scwin.processType=="TYPE13"){
				if(lc_jobgb.getValue()=="S"){
                    vObjGrd = "gr_InvoiceType13_s";
                } else if(lc_jobgb.getValue()=="A") {
                    vObjGrd = "gr_InvoiceType13_a";
                }                
			    sheetTitle = "Invoice List Type13";
			}else if(scwin.processType=="TYPE14"){
				vObjGrd = "gr_InvoiceType14";
				sheetTitle = "Invoice List Type14";
			}else if(scwin.processType=="TYPE15"){
				if(lc_type.getValue()=="1"){
                    vObjGrd = "gr_InvoiceType15_1";
                } else if(lc_type.getValue()=="2") {
                    vObjGrd = "gr_InvoiceType15_2";
                } else if(lc_type.getValue()=="3") {
                    vObjGrd = "gr_InvoiceType15_3";
                }
				sheetTitle = "Invoice List Type15";

			}else if(scwin.processType=="TYPE16"){
				vObjGrd = "gr_InvoiceType16";
				sheetTitle = "Invoice List Type16";
			}else if(scwin.processType=="TYPE17"){
				vObjGrd = "gr_InvoiceType17";
				sheetTitle = "Invoice List Type17";
			}else if(scwin.processType=="TYPE18"){
				vObjGrd = "gr_InvoiceType18";
				sheetTitle = "Invoice List Type18";
			}else if(scwin.processType=="TYPE19"){
				vObjGrd = "gr_InvoiceType19";
				sheetTitle = "Invoice List Type19";
			}

    		var objGrd = eval(vObjGrd);

    		if(scwin.processType=="TYPE11"){
    		//TYPE11일때만 그리드 그대로 엑셀 출력되도록	
    			// cfGridToExcel(objGrd, sheetTitle, sheetTitle, 1+4+8+16+32);
                await $c.data.downloadGridViewExcel(objGrd, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle, hiddenVisible:true });
    		}else if(scwin.processType=="TYPE3"){
				if(lc_jobgb.getValue()=="A") {
                    // cfGridToExcel(objGrd, sheetTitle, sheetTitle, 2+4+8+16+32);
                    await $c.data.downloadGridViewExcel(objGrd, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle, hiddenVisible:true });    
                } else {
                    // cfGridToExcel(objGrd, sheetTitle, sheetTitle, 2+4+8+16+32);
                    await $c.data.downloadGridViewExcel(objGrd, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle, hiddenVisible:true, removeColumns : "1" });    
                }
    		}else if(scwin.processType=="TYPE7"){
                await $c.data.downloadGridViewExcel(objGrd, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle, hiddenVisible:true, removeColumns : "28,29,30,31,32,33,34,35,36,40" });    
            } else {
				// cfGridToExcel(objGrd, sheetTitle, sheetTitle, 2+4+8+16+32);
                await $c.data.downloadGridViewExcel(objGrd, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle, hiddenVisible:true });    
    		}
		}
  	}else {
		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
  	}

  };

//Customer
scwin.udc_clntNo_onblurCodeEvent = function (e) {
    if (ed_cncd.originalValue == ed_cncd.realValue) {
        return;
    }
    if (ed_cncd.getValue() == "") {
        txt_cnnm.setValue("");
    } else {
        udc_clntNo.ilCommonPopUp(
            scwin.udc_clntNo_onblurCodeEvent_callBackFunc
            , ed_cncd.getValue() //pCode
            , "" //pName
            , "T" //pWinCloseTF // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
            , "5"//pDispCnt
            , "Customer"//pTitle
            , null//pWidth
            , null //pHidden
            , null //pWhere
            , "500" // pW
            , "500" //pH
            , null //pTop
            , null //pLeft
            , null //pExistTF
            , "F" //pAllSearchTF
            , null //pWtitleSearch
            , null //pNoDataCloseTF
            , null //tmpDataSet
        )
    }

};

// udc Customer 코드 블러 이벤트 콜백
scwin.udc_clntNo_onblurCodeEvent_callBackFunc = function (data) {
    if (data[0] == "N/A") {
        ed_cncd.setValue("");
        txt_cnnm.setValue("");
    } else {
        ed_cncd.setValue(data[0]);
        txt_cnnm.setValue(data[1]);
    }
}

// udc Customer 네임 블러 이벤트
scwin.udc_clntNo_onblurNameEvent = function (e) {
    if (!txt_cnnm.realValue) {
        txt_cnnm.setValue(txt_cnnm.originalValue);
        return;
    }
    // 3. 값이 비어있으면 종료 (관련 코드 초기화 필요 시 추가)
    if (txt_cnnm.getValue() == "") {
        return;
    } else {
        // 1. 기준 업체명 (기존에 로드되어 있던 정식 명칭)
        let masterValue = txt_cnnm.originalValue;
        // 2. 현재 입력창에 보이는 실제 값 (realValue)
        let inputVal = (txt_cnnm.realValue || "").trim();
        // 5. 매칭 체크 (대소문자 무시, 한글 포함)
        // masterValue가 inputVal로 시작하는지 확인
        let isMatch = masterValue.toUpperCase().startsWith(inputVal.toUpperCase());
        if (isMatch) {
            // [TRUE] 일치할 경우: "aa" -> "AA LOGISTICS CO., LTD." 대문자 정식명칭 유지
            txt_cnnm.setValue(masterValue);
        } else {
            udc_clntNo.ilCommonPopUp(
                scwin.udc_clntNo_onblurNameEvent_callBackFunc
                , "" //pCode
                , txt_cnnm.getValue()  //pName
                , "T" //pWinCloseTF // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , "5"//pDispCnt
                , "Customer"//pTitle
                , null//pWidth
                , null //pHidden
                , null //pWhere
                , "500" // pW
                , "500" //pH
                , null //pTop
                , null //pLeft
                , null //pExistTF
                , "F" //pAllSearchTF
                , null //pWtitleSearch
                , null //pNoDataCloseTF
                , null //tmpDataSet
            )
        }
    };

};

