scwin.btn_add_onclick = function (e) {
    scwin.f_Copy();

};

scwin.f_Copy = function () {
    var temp;
    if(txt_dscd.getValue() != "")	{
        if( txt_dscds.getValue() == "" )
            temp = txt_dscd.getValue();
        else
            temp = ","+txt_dscd.getValue();
            txt_dscds.setValue(txt_dscds.getValue() + temp);
            txt_dscd.setValue("");
    }
};

scwin.btn_serial_onclick = function (e) {
    scwin.f_invoice();

};

scwin.f_invoice = function () {
// debugger;

	if(ds_InvoiceExcelType.getRowCount() > 0){	
    	if(ds_InvoiceExcelType.getCellData(ds_InvoiceExcelType.getRowPosition(),"blno") !=""){

    		var blno = ds_InvoiceExcelType.getCellData(ds_InvoiceExcelType.getRowPosition(),"blno");
    		var seaair = dma_SearchParam.get("seaair");
    		var iogb = ds_InvoiceExcelType.getCellData(ds_InvoiceExcelType.getRowPosition(),"iogb");

            var param = {
                seaair  : seaair,
                iogb    : iogb,
                blno    : blno
            };

            let strPath = "/ui/il/acc/acinv/ac_101_01_01b.xml";

            console.log("paramparam::", param);

         	// cfTabMenuUpdate( "/il/acc/acinv/ac_101_01_01b.jsp?seaair="+seaair+"&iogb="+iogb+"&blno="+blno , "Invoice ") ;
            $c.win.openMenu("Invoice ", strPath, "ac_101_01_01b.jsp",param);

        }
    }
	else{
    	alert("조회 먼저 하십시요.");
    	return;
	}
};

