scwin.fn_decodeHhio6 = function(value) {
    // value는 hhio 컬럼의 원본 값
    if (value === "I") return "수입";
    if (value === "O") return "수출";
    return "기타";
};

scwin.fn_decodeHhio8 = function(value) {
    // 가우스의 Decode와 동일한 로직
    switch(value) {
        case "I": return "IN";
        case "O": return "OUT";
        default : return value; // 혹은 "" (빈값)
    }
};

scwin.fn_decodeHhio9 = function(value) {
    if (value === "I") return "IN";
    if (value === "O") return "OUT";
    return value; // 조건에 없으면 원본 값 표시
};

scwin.fn_decodeIogb10 = function(value) {
    if (value == "I") return "IN";
    if (value == "O") return "OUT";
    return value; // 또는 ""
};

scwin.fn_decodeHhio5 = function(data) {
    // data는 해당 셀에 들어온 원본 값(hhio 컬럼 값)입니다.
    if (data === "I") {
        return "수입";
    } else if (data === "O") {
        return "수출";
    } else {
        return "기타";
    }
};

